import{_ as e,c as s,o as a,U as n}from"./chunks/framework.V7QYn7G9.js";const m=JSON.parse('{"title":"Database Schemas","description":"","frontmatter":{},"headers":[],"relativePath":"lesli/database/schema.md","filePath":"lesli/database/schema.md","lastUpdated":1707090984000}'),t={name:"lesli/database/schema.md"},i=n(`<h1 id="database-schemas" tabindex="-1">Database Schemas <a class="header-anchor" href="#database-schemas" aria-label="Permalink to &quot;Database Schemas&quot;">​</a></h1><p>The database structure of Lesli and all the engines must be documented and maintained within the respective engine in the following path: <em>engine_root/docs/database.md</em>. If you make any changes that add, remove or renumber any table, you <strong>must</strong> document it within this file, or your pull request will be rejected. At the current time, only changes to tables are being documented, so new columns or column name changes don&#39;t require you to modify <em>database.md</em>.</p><p>These changes must also meet all standards written below.</p><h2 id="collection-and-engine-numbering-standard" tabindex="-1">Collection and Engine Numbering Standard <a class="header-anchor" href="#collection-and-engine-numbering-standard" aria-label="Permalink to &quot;Collection and Engine Numbering Standard&quot;">​</a></h2><p>A rails migration must containt a number as a prefix that helps rails identify which migrations must be run and in which order. We take advantage of this behavior by replacing the default rails numeration for our custom one. The prefix number of each table must be a 8 digit decimal number that meets the format <strong>CC.EE.NN.TT.VV</strong> where:</p><br><p><strong>— CC</strong> is a 2-digit number that represents a the collection of the table. Engines that work within the same area have the same collection number. For Example <strong>CloudFocus</strong> (the task management system) and <strong>CloudNotes</strong> (the notes management system) are both under the <strong>03</strong> collection. There is a detailed list of all collections in the <a href="/about/ecosystem.html">Ecosystem section.</a>.</p><br><p><strong>— EE</strong> is a 2-digit number that identifies a specific engine within a collection. In our previous example, CloudFocus is <strong>03.03</strong> and CloudNotes is <strong>03.05</strong> There is a detailed list of all engines (implemented or not) in the <a href="/about/ecosystem.html">Ecosystem section.</a>.</p><br><p><strong>— NN</strong> is a 2-digit number that identifies a namespace within the engine. Namespaces must e unique within the engine, but 2 different engines can (and will in some cases) have the same namespace. For example, the table <strong>cloud_focus_task</strong> and all its child tables are all within the <strong>03.05.10</strong> namespace.</p><br><p><strong>— TT</strong> is a 2-digit number that identifies a specific table within the namespace. For example, the table <strong>cloud_focus_task</strong> has the code <strong>03.05.10.01</strong> while the table <strong>cloud_focus_task_activities</strong> has the code <strong>03.05.10.04</strong>.</p><br><p><strong>— VV</strong> is a 2-digit number that identifies the version of the migration, this number correspond to the folder version inside the migration folder.</p><br><h2 id="namespace-and-table-number-standard-and-required-tables" tabindex="-1">Namespace and Table Number Standard and Required Tables <a class="header-anchor" href="#namespace-and-table-number-standard-and-required-tables" aria-label="Permalink to &quot;Namespace and Table Number Standard and Required Tables&quot;">​</a></h2><p>To calculate engines and tables numerations, you should meet the following requirements:</p><p><strong>1.</strong> Each engine has an account table, that isolates the resources to each account, this table is always the code <strong>CC.EE.00.01</strong></p><p><strong>2.</strong> After the account, the catalogs namespace is used with the numeration <strong>CC.EE.01</strong>. A catalog table is a table that has only data, with no foreign key other than the account, and is used to provide data to other more complex tables. Your first catalog table must have the code <strong>CC.EE.01.01</strong></p><p><strong>3.</strong> The workflows namespace is next and it contains the codes <strong>CC.EE.02.TT</strong> starting with the table <strong>CC.EE.02.01</strong>: <strong>cloud_ENGINE_workflows</strong></p><p><strong>4.</strong> The custom_fields namespace is next and it contains the codes <strong>CC.EE.03.TT</strong> starting with the table <strong>CC.EE.03.01</strong>: <strong>cloud_ENGINE_custom_fields</strong></p><p><strong>5.</strong> The custom_validations namespace is next and it contains the codes <strong>CC.EE.04.TT</strong> starting with the table <strong>CC.EE.04.01</strong>: <strong>cloud_ENGINE_custom_validations</strong></p><p><strong>6.</strong> The dashboards namespace is next and it contains the codes <strong>CC.EE.05.TT</strong> starting with the table <strong>CC.EE.05.01</strong>: <strong>cloud_ENGINE_dashboards</strong></p><p>The codes <strong>CC.EE.06.TT</strong> to <strong>CC.EE.09.TT</strong> are reserved for future usage.</p><p>After this you can create any number of tables depending on the amount of resources you will have in your engine. Starting with the namespace <strong>CC.EE.10</strong>, these tables have the following format:</p><ul><li><strong>CC.EE.10.00</strong> Main table</li><li><strong>CC.EE.10.01</strong> Main table actions</li><li><strong>CC.EE.10.02</strong> Main table activities</li><li><strong>CC.EE.10.03</strong> Main table discussions</li><li><strong>CC.EE.10.04</strong> Main table subscribers</li><li><strong>CC.EE.10.05</strong> Main table files</li><li><strong>CC.EE.10.06</strong> Main table custom_field_values</li><li><strong>CC.EE.10.07</strong> to <strong>10.09</strong> are reserved</li><li><strong>CC.EE.10.10</strong> and higher are for your custom tables</li></ul><h2 id="example-of-database-md-file" tabindex="-1">Example of database.md file <a class="header-anchor" href="#example-of-database-md-file" aria-label="Permalink to &quot;Example of database.md file&quot;">​</a></h2><p>Here is an example of a database.md file for the CloudHelp engine (code <strong>07.02</strong>) (this is just an example, for the real database documentation you should review the <strong>DATABASE STRUCTURE</strong> section):</p><div class="language-textplain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">textplain</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>    00.01. help/account                     # Required table</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    01.01. help/catalogs                    # Required table</span></span>
<span class="line"><span>    01.02. help/catalog/ticket_categories </span></span>
<span class="line"><span>    01.03. help/catalog/ticket_priorities</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    02.01. help/workflows                   # Required table</span></span>
<span class="line"><span>    02.02. help/workflow/statuses           # Required table</span></span>
<span class="line"><span>    02.03. help/workflow/associations       # Required table</span></span>
<span class="line"><span>    02.04. help/workflow/actions            # Required table</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    03.01. help/custom_fields               # Required table</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    04.01. help/custom_validations          # Required table</span></span>
<span class="line"><span>    04.02. help/custom_validation/rules     # Required table</span></span>
<span class="line"><span>    04.03. help/custom_validation/fields    # Required table</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    05.01. help/dashboards                  # Required table</span></span>
<span class="line"><span>    05.02. help/dasboard/components         # Required table</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    # Note that here 06.XX to 09.XX are unused and reserved</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    10.00. help/tickets</span></span>
<span class="line"><span>    10.01. help/ticket/actions              # Required child table for tickets</span></span>
<span class="line"><span>    10.02. help/ticket/activities           # Required child table for tickets</span></span>
<span class="line"><span>    10.03. help/ticket/discussions          # Required child table for tickets</span></span>
<span class="line"><span>    10.04. help/ticket/subscribers          # Required child table for tickets</span></span>
<span class="line"><span>    10.05. help/ticket/files                # Required child table for tickets</span></span>
<span class="line"><span>    10.06. help/ticket/custom_field_values  # Required child table for tickets</span></span>
<span class="line"><span>    10.10. help/ticket/timelines</span></span>
<span class="line"><span>    10.11. help/ticket/assignments</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    11.00. help/slas</span></span>
<span class="line"><span>    11.01. help/sla/actions                 # Required child table for tickets</span></span>
<span class="line"><span>    11.02. help/sla/activities              # Required child table for tickets</span></span>
<span class="line"><span>    11.03. help/sla/discussions             # Required child table for tickets</span></span>
<span class="line"><span>    11.04. help/sla/subscribers             # Required child table for tickets</span></span>
<span class="line"><span>    11.05. help/sla/files                   # Required child table for tickets</span></span>
<span class="line"><span>    11.06. help/sla/custom_field_values     # Required child table for tickets</span></span>
<span class="line"><span>    11.10. help/sla/associations</span></span></code></pre></div>`,30),o=[i];function l(r,p,c,d,h,g){return a(),s("div",null,o)}const b=e(t,[["render",l]]);export{m as __pageData,b as default};
